const localTime=value=>value?new Date(value).toLocaleString("en-GB",{timeZone:"Europe/London",weekday:"short",day:"numeric",month:"short",hour:"2-digit",minute:"2-digit"}):"Time TBC";
const allScheduleGames=()=>{const seen=new Map();(DATA.games||[]).forEach(g=>{if(!seen.has(String(g.id)))seen.set(String(g.id),{id:g.id,date:safeDate(g),startTimeUTC:g.startTimeUTC,state:g.finished?"FINAL":"FUT",home:g.location==="Home"?g.team:g.opponent,away:g.location==="Away"?g.team:g.opponent,homeScore:g.location==="Home"?g.gf:g.ga,awayScore:g.location==="Away"?g.gf:g.ga,broadcasts:[]})});(DATA.daily?.games||[]).forEach(g=>seen.set(String(g.id),{...g,date:safeDate(g)}));return [...seen.values()].sort((a,b)=>(a.startTimeUTC||safeDate(a)||"").localeCompare(b.startTimeUTC||safeDate(b)||""))};
function today(){const daily=DATA.daily||{},gs=daily.games||[],tracked=gs.filter(g=>teams().includes(g.home)||teams().includes(g.away));el("today-date").textContent=daily.currentDate?new Date(daily.currentDate+"T12:00:00").toLocaleDateString("en-GB",{weekday:"long",day:"numeric",month:"long",year:"numeric"}):"Latest NHL update";el("today-cards").innerHTML=metric("Games",gs.length,"Current NHL slate")+metric("Your games",tracked.length,"Tracked teams")+metric("NHL teams",DATA.standings.length,"League coverage")+metric("Local time",new Date().toLocaleTimeString("en-GB",{hour:"2-digit",minute:"2-digit"}),"Times shown locally");el("today-games").innerHTML=gs.length?gs.map(gameLine).join(""):`<p class="notice">No games are scheduled in the current NHL window.</p>`;el("today-teams").innerHTML=teams().map(t=>{const g=tracked.find(x=>x.home===t||x.away===t),s=DATA.teams[t];return `<div class="rank-row"><strong>${TEAM_NAMES[t]}</strong><span>${g?`${g.away} at ${g.home} · ${localTime(g.startTimeUTC)}`:`${s.points} pts · ${s.w}-${s.l}-${s.otl}`}</span></div>`}).join("");el("today-glance").innerHTML=table(["Team","Record","PTS","GD","Last 10"],teams().map(t=>{const s=DATA.teams[t],r=record(s.last10);return[TEAM_NAMES[t],`${s.w}-${s.l}-${s.otl}`,s.points,signed(s.gd),`${r.w}-${r.l}-${r.otl}`]}))}
function gameLine(g){const score=g.homeScore!=null?`${g.away} ${g.awayScore} — ${g.homeScore} ${g.home}`:`${g.away} at ${g.home}`;return `<button type="button" class="rank-row game-link" data-open-game="${g.id}"><strong>${score}</strong><span>${localTime(g.startTimeUTC)}${g.broadcasts?.length?` · ${g.broadcasts.join(", ")}`:""}</span></button>`}
let GAME_REQUEST=0;
const officialValue=v=>typeof v==="object"&&v?v.default||v.en||Object.values(v)[0]||"":v??"";
const fullOfficialName=p=>[officialValue(p?.firstName),officialValue(p?.lastName)].filter(Boolean).join(" ")||officialValue(p?.name)||"Unknown player";
const gameTeamName=t=>teamStanding(t)?.name||TEAM_NAMES[t]||t;
const periodName=p=>p?.periodType==="OT"?`OT${p.number>4?p.number-3:""}`:p?.periodType==="SO"?"Shootout":`Period ${p?.number||"—"}`;
function gameStatus(g,landing){const state=landing?.gameState||g.state,clock=landing?.clock,period=landing?.periodDescriptor;if(["OFF","FINAL"].includes(state))return "Final";if(["LIVE","CRIT"].includes(state))return `${periodName(period)} · ${clock?.inIntermission?"Intermission":clock?.timeRemaining||"Live"}`;return localTime(landing?.startTimeUTC||g.startTimeUTC)}
function gameHero(g,landing){const away=landing?.awayTeam||{abbrev:g.away,score:g.awayScore,logo:teamLogo(g.away)},home=landing?.homeTeam||{abbrev:g.home,score:g.homeScore,logo:teamLogo(g.home)},state=landing?.gameState||g.state,played=["OFF","FINAL","LIVE","CRIT"].includes(state);return `<section class="game-hero"><div class="game-club"><img src="${away.logo||teamLogo(away.abbrev)}" alt=""><strong>${gameTeamName(away.abbrev)}</strong><span class="game-score">${played?away.score??0:"—"}</span></div><div class="game-state"><strong>${gameStatus(g,landing)}</strong><span>${officialValue(landing?.venue)||g.venue||"Venue TBC"}</span><span>${(landing?.tvBroadcasts||g.broadcasts||[]).map(x=>x.network||x).filter(Boolean).join(", ")||"Broadcast information TBC"}</span></div><div class="game-club home"><img src="${home.logo||teamLogo(home.abbrev)}" alt=""><strong>${gameTeamName(home.abbrev)}</strong><span class="game-score">${played?home.score??0:"—"}</span></div></section>`}
function gameContext(code){const s=teamStanding(code),m=mp().teams.find(x=>x.team===code),last=DATA.teams?.[code]?.last10||[],r=record(last);return `<article class="panel game-context"><div class="game-context-head"><img src="${teamLogo(code)}" alt=""><h3>${gameTeamName(code)}</h3></div><div class="game-context-stats"><span><strong>${s?`${s.w}-${s.l}-${s.otl}`:"—"}</strong> Season</span><span><strong>${last.length?`${r.w}-${r.l}-${r.otl}`:"—"}</strong> Last 10</span><span><strong>${m?`${mpPct(m.xgPct).toFixed(1)}%`:"—"}</strong> xG share</span></div></article>`}
function gamesCentre(){const gs=allScheduleGames().slice().reverse();el("game-select").innerHTML=gs.map(g=>`<option value="${g.id}">${safeDate(g)||"Date TBC"} · ${g.away} at ${g.home}</option>`).join("");el("game-refresh").onclick=refreshGameView;renderGame()}
